mapper.select:
select

from bio_sample_test_one_result_tb

    and sample_code=#{sampleCode,jdbcType=VARCHAR}
    and test_identify_primer=#{testIdentifyPrimer,jdbcType=VARCHAR}
    and test_method=#{testMethod,jdbcType=VARCHAR}
    and test_edit_type=#{testEditType,jdbcType=VARCHAR}

        and    test_no_trans_identity_primer=#{testNoTransIdentityPrimer,jdbcType=VARCHAR}


        and   test_is_gene_modify_positive=#{testIsGeneModifyPositive,jdbcType=VARCHAR}

    and test_if_fixed_point=#{testIfFixedPoint,jdbcType=VARCHAR}
    and test_if_copy_insert=#{testIfCopyInsert,jdbcType=VARCHAR}
    and test_fixed_point_type=#{testFixedPointType,jdbcType=VARCHAR}
    and test_donor_residue_info=#{testDonorResidueInfo,jdbcType=VARCHAR}

    and test_insertion_site=#{testInsertionSite,jdbcType=VARCHAR}
    and test_elisa_result=#{testElisaResult,jdbcType=VARCHAR}
    and test_qbzr_seq=#{testQbzrSeq,jdbcType=VARCHAR}
    and test_edit_residue_info=#{testEditResidueInfo,jdbcType=VARCHAR}
    and test_user_id=#{testUserId,jdbcType=NUMERIC}
    and test_user_name=#{testUserName,jdbcType=VARCHAR}
    and test_time=#{testTime,jdbcType=VARCHAR}
    and test_channel=#{testChannel,jdbcType=VARCHAR}
    and task_num=#{taskNum,jdbcType=VARCHAR}
    and upload_num=#{uploadNum,jdbcType=VARCHAR}
    and remark is not null


order by id desc
